  "mobileHeader": "<header class=\"mobile-header\">\r\n        <div class=\"mobile-logo\">\r\n          <img src=\"/logo.svg?v=j-monogram-20260717\" alt=\"JuntAPP Logo\" style=\"height: 32px;\" />\r\n          <span>Junt<strong>APP</strong></span>\r\n        </div>\r\n        <div class=\"mobile-header-actions\" style=\"display: flex; align-items: center; gap: 12px;\">\r\n          <!-- Notification Toggle (Mobile) -->\r\n          <button class=\"mobile-bell-btn\" id=\"mobileBellToggle\" aria-label=\"Ver Notificaciones\" style=\"background: none; border: none; color: var(--text); padding: 8px; cursor: pointer; display: flex; align-items: center; justify-content: center; position: relative;\">\r\n            <div class=\"bell-icon-wrapper\" style=\"position: relative; display: flex; align-items: center; justify-content: center; width: 22px; height: 22px;\">\r\n              <svg aria-hidden=\"true\" xmlns=\"http://www.w3.org/2000/svg\" width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9\"/><path d=\"M13.73 21a2 2 0 0 1-3.46 0\"/></svg>\r\n              <span class=\"bell-badge\" id=\"mobileBellBadge\" style=\"display: none;\">0</span>\r\n            </div>\r\n          </button>\r\n          <button class=\"mobile-theme-btn\" id=\"mobileThemeToggle\" aria-label=\"Cambiar Tema\">\r\n            <svg class=\"icon-sun\" aria-hidden=\"true\" xmlns=\"http://www.w3.org/2000/svg\" width=\"20\" height=\"20\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"5\"/><line x1=\"12\" y1=\"1\" x2=\"12\" y2=\"3\"/><line x1=\"12\" y1=\"21\" x2=\"12\" y2=\"23\"/></svg>\r\n            <svg class=\"icon-moon\" aria-hidden=\"true\" xmlns=\"http://www.w3.org/2000/svg\" width=\"20\" height=\"20\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z\"/></svg>\r\n          </button>\r\n        </div>\r\n      </header>"
